// =============== AUTH ENDPOINTS ===============
export const authService = {
  register: (fullName, username, email, password, passwordConfirm, farmName) => apiClient.post('/auth/register', {
    fullName,
    username,
    email,
    password,
    passwordConfirm,
    farmName
  }),
  login: (username, password) => apiClient.post('/auth/login', {
    username,
    password
  }),
  refreshToken: () => apiClient.post('/auth/refresh-token'),
  changePassword: data => apiClient.post('/auth/change-password', data)
};

// =============== USER ENDPOINTS ===============
export const userService = {
  getCurrentUser: () => apiClient.get('/users/me'),
  getAllUsers: () => apiClient.get('/users'),
  getWorkers: () => apiClient.get('/users/workers'),
  updateUser: (userId, userData) => apiClient.put(`/users/${userId}`, userData),
  updateUserRole: (userId, roleId) => apiClient.put(`/users/${userId}/role`, {
    role_id: roleId
  }),
  lockUser: userId => apiClient.put(`/users/${userId}/lock`),
  unlockUser: userId => apiClient.put(`/users/${userId}/unlock`),
  resetPassword: userId => apiClient.post(`/users/${userId}/reset-password`),
  deleteUser: userId => apiClient.delete(`/users/${userId}`),
  // Update role by name (e.g., 'MANAGER') - used by Owner interface
  updateUserRoleByName: (userId, roleName) => apiClient.put(`/users/${userId}/role`, {
    role: roleName
  }),
  // Remove user from farm (set farm_id = NULL)
  removeFromFarm: userId => apiClient.put(`/users/${userId}/remove-from-farm`),
  // Assign user to farm (set farm_id)
  assignToFarm: (userId, farmId) => apiClient.put(`/users/${userId}/assign-to-farm`, {
    farm_id: farmId
  }),
  changePassword: (oldPassword, newPassword) => apiClient.post('/users/change-password', {
    oldPassword,
    newPassword
  }),
  updateProfile: userData => apiClient.put('/users/me', userData),
  updateProfileAvatar: formData => apiClient.post('/users/me/avatar', formData, {
    headers: {
      'Content-Type': 'multipart/form-data'
    }
  })
};

