  { method: 'delete', pattern: /^\/ponds\/\d+$/, success: 'Xïŋ―a ao nuïŋ―i thïŋ―nh cïŋ―ng', error: 'Khïŋ―ng thïŋ― xïŋ―a ao nuïŋ―i' },
