  { method: 'post', pattern: /^\/diseases$/, success: 'Thïŋ―m bïŋ―nh thïŋ―nh cïŋ―ng', error: 'Khïŋ―ng thïŋ― thïŋ―m bïŋ―nh' },
  { method: 'put', pattern: /^\/diseases\/\d+$/, success: 'Cïŋ―p nhïŋ―t bïŋ―nh thïŋ―nh cïŋ―ng', error: 'Khïŋ―ng thïŋ― cïŋ―p nhïŋ―t bïŋ―nh' },
