]

const isAuthRoute = (url = '') => {
  return url.startsWith('/auth/login') || url.startsWith('/auth/refresh-token')
}

const shouldShowAutoToast = (config = {}) => {
  const method = (config.method || '').toLowerCase()
  if (!MUTATING_METHODS.has(method)) return false
  if (config.toast === false || config.skipToast === true) return false
  if (isAuthRoute(config.url || '')) return false
  return true
}

const extractServerMessage = (payload) => {
  if (!payload || typeof payload !== 'object') return null
  return payload.message || payload.error || payload?.data?.message || null
}

const normalizePath = (url = '') => {
  return String(url).split('?')[0]
}

const getRouteToastMessage = (config = {}) => {
  const method = (config.method || '').toLowerCase()
  const path = normalizePath(config.url)
  return ROUTE_TOAST_MESSAGES.find((item) => item.method === method && item.pattern.test(path)) || null
}

// Add token to requests
apiClient.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Handle responses
apiClient.interceptors.response.use(
  (response) => {
    const { config, data } = response
    if (shouldShowAutoToast(config)) {
      const method = (config.method || '').toLowerCase()
      const routeToast = getRouteToastMessage(config)
      const successMessage = typeof config.toast === 'object' && config.toast?.success
        ? config.toast.success
        : (routeToast?.success || extractServerMessage(data) || DEFAULT_SUCCESS_BY_METHOD[method] || 'Thao tïŋ―c thïŋ―nh cïŋ―ng')

      pushToast({
        title: 'Thïŋ―nh cïŋ―ng',
        message: successMessage,
        type: 'success',
        duration: 3500,
      })
    }
    return response
  },
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      window.location.href = '/login';
    }

    const config = error.config || {}
    if (shouldShowAutoToast(config)) {
      const routeToast = getRouteToastMessage(config)
      const errorMessage = typeof config.toast === 'object' && config.toast?.error
        ? config.toast.error
        : (routeToast?.error || extractServerMessage(error.response?.data) || error.message || 'Thao tïŋ―c thïŋ―t bïŋ―i')

      pushToast({
        title: 'Thïŋ―t bïŋ―i',
        message: errorMessage,
        type: 'error',
        duration: 5000,
      })
    }

    return Promise.reject(error);
  }
);

